using System;

class Program
{
    static void Main(string[] args)
    {
        SayHello();
    }

    static void SayHello()
    {
        Console.WriteLine("Salam, Dünya!");
    }
}
// Output:
// Salam, Dünya!

using System;

class Program
{
    static void Main(string[] args)
    {
        PrintName("Ali", 20);
    }

    static void PrintName(string name, int age)
    {
        Console.WriteLine($"Ad: {name}, Yaş: {age}");
    }
}
// Output:
// Ad: Ali, Yaş: 20

using System;

class Program
{
    static void Main(string[] args)
    {
        int result = AddNumbers(5, 3);
        Console.WriteLine($"Cəm: {result}");
    }

    static int AddNumbers(int a, int b)
    {
        return a + b;
    }
}
// Output:
// Cəm: 8

using System;

class Program
{
    static void Main(string[] args)
    {
        double area = CalculateRectangleArea(5.5, 3.2);
        Console.WriteLine($"Düzbucaqlının sahəsi: {area}");
    }

    static double CalculateRectangleArea(double length, double width)
    {
        return length * width;
    }
}
// Output:
// Düzbucaqlının sahəsi: 17.6

